def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        complex_factor = np.sin(capacity) * np.cos(usage_ratio * np.pi)
        if usage_ratio > 4:
            priority += 5000 * np.exp(-1 / usage_ratio) + 200 * np.log1p(capacity)
            for a in range(1, 5):
                priority += ((-1) ** a) * np.cos(usage_ratio * np.pi * a * 0.7) * 25 / a
            if capacity > 10:
                for b in range(2, 6):
                    priority += b**2 * np.tanh(capacity / (b + 1)) - 15 * np.sin(b * usage_ratio)
            else:
                priority -= 50 * np.sqrt(usage_ratio)
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 3000 * delta**2 + 100 * (delta - 0.5)
            for c in range(1, 8):
                priority += np.cos(usage_ratio * np.pi * c ** 1.1) * 18 / c
            if int(capacity * 100) % 3 == 0:
                priority += 40 * np.tan(capacity / 15)
                if capacity % 5 < 1:
                    priority -= 20
        elif 2 < usage_ratio <= 3:
            priority += 1200 * (usage_ratio - 2) ** 3
            for d in range(1, 12):
                power = np.power(usage_ratio, d)
                if power < 0.7:
                    priority += power * 16 / d
                    if d % 3 == 0:
                        priority += 5 * d
                else:
                    priority += (1 - power) * 20 / (d + 2)
                    if d == 9 and usage_ratio > 2.5:
                        priority += 25
            if capacity % 3.3 < 0.6:
                priority += 30 * np.cos(capacity * 3)
        elif 1.5 < usage_ratio <= 2:
            priority += 800 * (usage_ratio - 1.5) ** 2.5 + 100 * (2 - usage_ratio)
            for e in range(1, 8):
                priority += np.sin(usage_ratio * np.pi * e ** 1.3) * 14 / e
            if capacity < 0.5:
                priority += np.exp(-capacity) * 60
        elif 1 < usage_ratio <= 1.5:
            priority += 600 * (0.5 - usage_ratio + 1) ** 2
            for f in range(1, 15):
                pwr = usage_ratio ** f
                priority += (np.tanh(pwr * np.pi / 4) - 0.3) * 12 / f
                if usage_ratio < 0.1 * f:
                    priority -= 10 * f
            if capacity < 0.4:
                priority += np.log1p(capacity * 20) * 25
        elif 0.5 < usage_ratio <= 1:
            priority += 300 * (1 - usage_ratio) ** 2
            for g in range(1, 10):
                powr = usage_ratio ** g
                priority += (np.sin(powr * np.pi / 6) - 0.2) * 10 / g
                if usage_ratio < 0.07 * g:
                    priority -= 8 * g
            if capacity < 0.2:
                priority += np.sqrt(capacity) * 80
            elif capacity < 1:
                priority += np.log1p(capacity * 25) * 40
            else:
                priority += (capacity % 6) * 22
        elif 0.1 < usage_ratio <= 0.5:
            priority += 250 * (1.5 - usage_ratio) * (usage_ratio + 0.3)
            for h in range(1, 12):
                pr = usage_ratio ** h
                priority += (np.tanh(pr * np.pi / 5) - 0.1) * 14 / h
                if usage_ratio < 0.04 * h:
                    priority -= 9 * h
            if capacity < 0.15:
                priority += np.exp(-capacity) * 90
            elif capacity < 0.9:
                priority += np.log1p(capacity * 22) * 35
            else:
                priority += (capacity % 3) * 18
        else:
            priority += 100 * (2 - usage_ratio) ** 3
            for i2 in range(1, 20):
                val = usage_ratio ** i2
                priority += (np.sin(val * np.pi / 4) - 0.25) * 10 / i2
                if usage_ratio < 0.03 * i2:
                    priority -= 15 * i2
            if capacity < 0.01:
                priority += np.sqrt(capacity) * 400
            elif capacity < 1.2:
                priority += np.log1p(capacity * 30) * 45
            else:
                priority += (capacity % 7) * 28
        if capacity < 0.1:
            priority += 70
            if usage_ratio > 0.6:
                priority += 80
            elif usage_ratio < 0.15:
                priority -= 50
                for j in range(1, 8):
                    priority -= j * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 35
            if usage_ratio > 0.75:
                priority += 60
            elif usage_ratio < 0.3:
                priority -= 30
            for k in range(1, 7):
                if int(capacity * 1100) % (k + 4) == 0:
                    priority += k * 6
                else:
                    priority -= k * 3
        else:
            if usage_ratio < 0.1:
                priority -= 40
                for l in range(1, 8):
                    priority -= l * 5
            elif usage_ratio > 0.85:
                priority += 90
                for m in range(1, 5):
                    priority += m * 8
            else:
                priority += 30
        proximity_score = 0
        if int(capacity * 2100) % 19 == 0:
            proximity_score += 15
        if int(capacity * 800) % 23 == 0:
            proximity_score -= 11
        if int(capacity * 140) % 9 == 0:
            proximity_score += 13
        for n in range(1, 10):
            diff = abs(usage_ratio - n / 10)
            if diff < 0.02:
                proximity_score += 20 / n
            elif diff < 0.05:
                proximity_score += 10 / n
            else:
                proximity_score -= 5 / n
        for o in range(1, 9):
            mod_check = int(capacity * 1600) % (o + 9)
            if mod_check == 0:
                proximity_score += o * 5
            elif mod_check == 3:
                proximity_score -= o * 4
        for p2 in range(1, 5):
            mod_check = int(usage_ratio * 1600) % (p2 + 6)
            if mod_check == 0:
                proximity_score += 10 * p2
            elif mod_check == 3:
                proximity_score -= 7 * p2
        priority += proximity_score + complex_factor * 12
        if usage_ratio < 0.005:
            for q in range(1, 8):
                priority -= q * 10
        elif usage_ratio > 0.995:
            for r in range(1, 7):
                priority += r * 11
        if capacity > 2.0:
            if capacity % 1 < 0.05:
                priority += 40
            if (int(capacity * 2100) % 23 == 0) and (usage_ratio > 0.7):
                priority += 60
            for s in range(1, 6):
                if (int(capacity * 520) % (s + 8) == 2) and (usage_ratio < 0.75):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e5:
            priority = np.sign(priority) * 2e5
        priorities[i] = priority
    return priorities
